import style from "./index.module.scss"
import template from './index.html'

export default class General extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return [];
  }
  attributeChangedCallback(name, oldValue, newValue) {
  }

  willLoad = () => {
    // const state = window.history.state
    // const {name, description} = state
    this.titleEle = this.shadowRoot?.querySelector("huanlin-title-description")
    this.titleEle.name = "General"
    this.titleEle.description = "Settings and options for your application."
  }
  connectedCallback() {
    this.classList.add("hydrated")
    this.willLoad()
    this.render()
  }
  disconnectedCallback() {
  }

  render = () => {
  }
}
